/*
Emitted at the beginning of the frame, before the RenderingServer updates all the Viewports.
*/
func OnFramePreDraw(cb func(), flags ...Signal.Flags) {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	once.Do(singleton)
	gd.ObjectConnect(gdclass.GetRenderingServer(self[0])[0], gd.NewStringName("frame_pre_draw"), gd.NewCallable(cb), int64(flags_together))
}

func (self class) FramePreDraw() Signal.Any {
	once.Do(singleton)
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`frame_pre_draw`))))
}

/*
Emitted at the end of the frame, after the RenderingServer has finished updating all the Viewports.
*/
func OnFramePostDraw(cb func(), flags ...Signal.Flags) {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	once.Do(singleton)
	gd.ObjectConnect(gdclass.GetRenderingServer(self[0])[0], gd.NewStringName("frame_post_draw"), gd.NewCallable(cb), int64(flags_together))
}

func (self class) FramePostDraw() Signal.Any {
	once.Do(singleton)
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`frame_post_draw`))))
}

